**Format with flextable for Word output**:


::: {.cell layout-align="center"}

```{.r .cell-code}
library(flextable)
library(tidyr)

# Pivot to wide format for easier table creation
ae_wide <- ae_summary %>%
  select(AESOC, AETERM, ARM, n, pct) %>%
  pivot_wider(
    names_from = ARM,
    values_from = c(n, pct),
    names_glue = "{ARM}_{.value}"
  ) %>%
  rename_with(~ gsub("_n$", " N", .), contains("_n")) %>%
  rename_with(~ gsub("_pct$", " %", .), contains("_pct"))

if (knitr::pandoc_to() %in% c("html", "html4", "html5")) {
  ae_table <- flextable(ae_wide) %>%
    set_header_labels(AESOC = "System Organ Class", AETERM = "Preferred Term") %>%
    theme_vanilla() %>% autofit() %>%
    add_footer_lines("Table 14.3.1: AEs by SOC and PT – Safety Population")
  ae_table
} else {
  knitr::kable(ae_wide, caption = "Table 14.3.1: Adverse Events by System Organ Class and Preferred Term")
}
```

